{
  "name": "Emerald Intelligence - Professional AI Chatbot",
  "description": "A production-grade, academic-standard AI chatbot interface featuring a clean green-and-white theme, persistent sidebar history, and integrated Gemini reasoning."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type Role = 'user' | 'assistant';

export interface Message {
  id: string;
  role: Role;
  content: string;
  timestamp: Date;
}

export interface ChatSession {
  id: string;
  title: string;
  messages: Message[];
  createdAt: Date;
}

export interface UserProfile {
  name: string;
  email: string;
  role: string;
}

import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

export const generateAIResponse = async (prompt: string, history: { role: string; parts: { text: string }[] }[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: [
        ...history,
        { role: 'user', parts: [{ text: prompt }] }
      ],
      config: {
        systemInstruction: "You are a professional academic assistant. Provide clean, concise, and structured responses. Avoid slang. Focus on accuracy and professional tone.",
        temperature: 0.7,
        topP: 0.8,
        topK: 40
      }
    });

    return response.text || "I'm sorry, I couldn't process that request.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Technical Error: Unable to reach the AI engine. Please check your network or API configuration.";
  }
};

