      content,
      timestamp: new Date(),
      imageUrl: image?.url
    };

    setSessions(prev => prev.map(s => {
      if (s.id === activeSessionId) {
        const isFirstMessage = s.messages.length === 0;
        let newTitle = s.title;
        if (isFirstMessage) {
          newTitle = image ? "Visual Identification" : content.slice(0, 25) + (content.length > 25 ? '...' : '');
        }
        return { ...s, messages: [...s.messages, userMsg], title: newTitle };
      }
      return s;
    }));

    setIsLoading(true);

    const activeSession = sessions.find(s => s.id === activeSessionId);

    // Prepare history correctly for the new media-enabled service
    const apiHistory = (activeSession?.messages || []).map(m => ({
      role: m.role,
      parts: [{ text: m.content }]
    }));

    const aiResponseText = await generateAIResponse(
      content, 
      apiHistory, 
      image ? { mimeType: image.mimeType, data: image.data } : undefined
    );

    const assistantMsg: Message = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiResponseText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s
    ));

    setIsLoading(false);
  };

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-[#fcfdfc] overflow-hidden">
      <Sidebar 
        sessions={sessions} 
        activeSessionId={activeSessionId} 
        onNewChat={handleNewChat}
        onSelectSession={handleSelectSession}
        user={MOCK_USER}
      />

      <main className="flex-1 flex flex-col relative h-full">
        <header className="h-20 border-b border-emerald-50 flex items-center justify-between px-10 bg-white/60 backdrop-blur-xl sticky top-0 z-10">
          <div className="flex items-center gap-4">
            <div className="w-10 h-10 bg-emerald-600 rounded-2xl flex items-center justify-center shadow-lg shadow-emerald-200">
              <img src="https://img.icons8.com/ios-filled/50/ffffff/leaf.png" className="w-6 h-6" alt="Logo" />
            </div>
            <div>
              <h1 className="text-emerald-950 font-black text-xl tracking-tight leading-none mb-1">EMERALD BOTANICAL</h1>
              <p className="text-[10px] text-emerald-600/60 font-bold uppercase tracking-[0.3em]">{activeSession?.title || 'System Idle'}</p>
            </div>
          </div>
          <div className="flex items-center gap-3">
             <div className="flex items-center gap-2 px-3 py-1.5 bg-emerald-50 rounded-full border border-emerald-100">
               <span className="w-2 h-2 bg-emerald-500 rounded-full animate-pulse"></span>
               <span className="text-[10px] font-bold text-emerald-700 uppercase tracking-widest">Vision Engine Active</span>
             </div>
          </div>
        </header>

        <ChatWindow 
          messages={activeSession?.messages || []} 
          isLoading={isLoading} 
        />

        <ChatInput onSend={handleSendMessage} disabled={isLoading} />
      </main>
    </div>
  );
};

