import { GoogleGenAI, GenerateContentResponse } from "@google/genai";

export interface MediaPart {
  inlineData: {
    mimeType: string;
    data: string;
  };
}

export const generateAIResponse = async (
  prompt: string, 
  history: { role: string; parts: ( { text: string } | MediaPart )[] }[],
  image?: { mimeType: string; data: string }
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  try {
    const contents: any[] = [...history];
    const currentParts: any[] = [{ text: prompt }];

    if (image) {
      currentParts.push({
        inlineData: {
          mimeType: image.mimeType,
          data: image.data,
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: `You are the "Emerald Botanical Expert," a professional yet accessible plant scientist.
        Your goal is to provide highly accurate botanical analysis in a clean, professional, and easy-to-read "Report" format.

        CORE TASKS:
        1. DISEASE DIAGNOSIS: Identify pathogens or environmental stress. Provide clear symptoms, causes, and a step-by-step treatment plan.
        2. SPACE RECOMMENDATION: Analyze environment photos and suggest 3 specific plants with their care requirements.
        3. PLANT PROFILES: Provide advantages, disadvantages, and growth stats (Light, Water, Soil, Temperature).

        OUTPUT STRUCTURE (REQUIRED):
        Use the following Markdown headers and icons:
        - ## 🌿 Overview: (Brief identification or summary)
        - ## 🏥 Diagnosis & Health: (If applicable)
        - ## 🛠️ Action Plan: (Step-by-step advice)
        - ## 📊 Technical Specifications: (Use a markdown table for requirements like pH, Light, etc.)
        - ## ✅ Pros & ❌ Cons: (Brief comparison)

        TONE:
        - Professional but encouraging.
        - Avoid overly dense academic jargon; keep it actionable.
        - Use bold text for emphasis.
        - If a user sends a non-plant photo, politely explain you are a botanical specialist.`,
        temperature: 0.5,
        topP: 0.8,
      }
    });

    return response.text || "I apologize, the botanical engine could not process this specimen.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Diagnostic Error: I encountered an issue analyzing the specimen. Please ensure the lighting is adequate and the subject is in focus.";
  }
};

