    }
  };

  const handleSendMessage = async (content: string, image?: { mimeType: string, data: string, url: string }) => {
    if (!activeSessionId) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content,
      timestamp: new Date(),
      imageUrl: image?.url
    };

    setSessions(prev => prev.map(s => {
      if (s.id === activeSessionId) {
        const isFirstMessage = s.messages.length === 0;
        let newTitle = s.title;
        if (isFirstMessage) {
          newTitle = image ? "Visual Identification" : content.slice(0, 25) + (content.length > 25 ? '...' : '');
        }
        return { ...s, messages: [...s.messages, userMsg], title: newTitle };
      }
      return s;
    }));

    setIsLoading(true);

    const activeSession = sessions.find(s => s.id === activeSessionId);
    const apiHistory = (activeSession?.messages || []).map(m => ({
      role: m.role,
      parts: [{ text: m.content }]
    }));

    const aiResponseText = await generateAIResponse(
      content, 
      apiHistory, 
      image ? { mimeType: image.mimeType, data: image.data } : undefined
    );

    const assistantMsg: Message = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiResponseText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s
    ));

    setIsLoading(false);
  };

  if (!currentUser) {
    return <AuthPortal />;
  }

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-[#f8fbf9] overflow-hidden">
      <Sidebar 
        sessions={sessions} 
        activeSessionId={activeSessionId} 
        onNewChat={handleNewChat}
        onSelectSession={handleSelectSession}
        automationEnabled={automationEnabled}
        onToggleAutomation={handleToggleAutomation}
      />

      <main className="flex-1 flex flex-col relative h-full">
        {showNotification && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[60] bg-emerald-900 text-white px-6 py-3 rounded-2xl shadow-2xl flex items-center gap-3 animate-in fade-in slide-in-from-top-4">
            <CheckCircle size={18} className="text-emerald-400" />
            <span className="text-sm font-bold tracking-tight">{showNotification}</span>
          </div>
        )}

        <header className="h-24 border-b border-emerald-50 flex items-center justify-between px-10 bg-white/70 backdrop-blur-2xl sticky top-0 z-10 shadow-sm shadow-emerald-900/5">
          <div className="flex items-center gap-4">
            <div className="w-12 h-12 bg-emerald-600 rounded-3xl flex items-center justify-center shadow-xl shadow-emerald-200 rotate-3">
              <img src="https://img.icons8.com/ios-filled/100/ffffff/leaf.png" className="w-7 h-7" alt="Emerald Logo" />
            </div>
            <div>
              <div className="flex items-center gap-2">
                <h1 className="text-emerald-950 font-black text-2xl tracking-tighter leading-none">EMERALD.AI</h1>
                <div className="px-2 py-0.5 bg-emerald-100 rounded text-[9px] font-black text-emerald-800 uppercase tracking-widest">v2.5</div>
              </div>
              <p className="text-[10px] text-emerald-600/60 font-black uppercase tracking-[0.4em] mt-1">
                {activeSession?.title || 'System Initializing...'}
              </p>
            </div>
          </div>

          <div className="hidden md:flex items-center gap-6">
             <div className="flex flex-col items-end">
               <span className="text-[10px] font-black text-emerald-950/30 uppercase tracking-[0.2em]">Engine Status</span>
               <span className="text-xs font-bold text-emerald-600 flex items-center gap-2">
                 Neural Vision Ready
                 <span className="w-2 h-2 bg-emerald-500 rounded-full animate-ping"></span>
               </span>
             </div>
             <div className="h-10 w-[1px] bg-emerald-50"></div>
