                <Mail size={16} className={automationEnabled ? "text-emerald-600" : "text-gray-300"} />
                <span className={`text-[11px] font-bold uppercase tracking-wider ${automationEnabled ? "text-emerald-950" : "text-gray-400"}`}>
                  {automationEnabled ? "Automation Active" : "Automation Idle"}
                </span>
             </div>
          </div>
        </header>

        <ChatWindow 
          messages={activeSession?.messages || []} 
          isLoading={isLoading} 
        />

        <ChatInput onSend={handleSendMessage} disabled={isLoading} />
