import React, { useState, useCallback, useEffect } from 'react';
import Sidebar from './components/Sidebar';
import ChatWindow from './components/ChatWindow';
import ChatInput from './components/ChatInput';
import AuthPortal from './components/Auth/AuthPortal';
import { AuthProvider, useAuth } from './context/AuthContext';
import { ChatSession, Message } from './types';
import { generateAIResponse } from './services/geminiService';
import { Mail, CheckCircle, Search, Settings, Activity } from 'lucide-react';

const MainApp: React.FC = () => {
  const { currentUser } = useAuth();
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [automationEnabled, setAutomationEnabled] = useState(true);
  const [showNotification, setShowNotification] = useState<string | null>(null);

  useEffect(() => {
    if (currentUser && sessions.length === 0) {
      handleNewChat();
    }
  }, [currentUser]);

  const handleNewChat = useCallback(() => {
    const newSession: ChatSession = {
      id: crypto.randomUUID(),
      title: "Specimen " + (sessions.length + 1).toString().padStart(3, '0'),
      messages: [],
      createdAt: new Date(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
  }, [sessions.length]);

  const handleSelectSession = useCallback((id: string) => {
    setActiveSessionId(id);
  }, []);

  const handleToggleAutomation = (enabled: boolean) => {
    setAutomationEnabled(enabled);
    if (enabled) {
      setShowNotification("Automation Synced: Seasonal reports active.");
      setTimeout(() => setShowNotification(null), 3000);
    }
  };

  const handleSendMessage = async (content: string, image?: { mimeType: string, data: string, url: string }) => {
    if (!activeSessionId) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content,
      timestamp: new Date(),
      imageUrl: image?.url
    };

    setSessions(prev => prev.map(s => {
      if (s.id === activeSessionId) {
        const isFirstMessage = s.messages.length === 0;
        let newTitle = s.title;
        if (isFirstMessage) {
          newTitle = image ? "Visual Identity" : content.slice(0, 18).toUpperCase();
        }
        return { ...s, messages: [...s.messages, userMsg], title: newTitle };
      }
      return s;
    }));

    setIsLoading(true);

    const activeSession = sessions.find(s => s.id === activeSessionId);
    const apiHistory = (activeSession?.messages || []).map(m => ({
      role: m.role,
      parts: [{ text: m.content }]
    }));

    const aiResponseText = await generateAIResponse(
      content, 
      apiHistory, 
      image ? { mimeType: image.mimeType, data: image.data } : undefined
    );

    const assistantMsg: Message = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiResponseText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s
    ));

    setIsLoading(false);
  };

  if (!currentUser) {
    return <AuthPortal />;
  }

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-[#fcfdfd] overflow-hidden selection:bg-emerald-500/20">
      <Sidebar 
        sessions={sessions} 
        activeSessionId={activeSessionId} 
        onNewChat={handleNewChat}
        onSelectSession={handleSelectSession}
        automationEnabled={automationEnabled}
        onToggleAutomation={handleToggleAutomation}
      />

      <main className="flex-1 flex flex-col relative h-full">
        {showNotification && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[60] bg-[#022218] text-emerald-400 px-8 py-3.5 rounded-full shadow-[0_20px_50px_rgba(0,0,0,0.3)] border border-emerald-900/50 flex items-center gap-3 animate-in fade-in slide-in-from-top-4">
            <CheckCircle size={18} />
            <span className="text-xs font-black uppercase tracking-widest">{showNotification}</span>
          </div>
        )}

        <header className="h-20 flex items-center justify-between px-10 bg-white/40 backdrop-blur-xl sticky top-0 z-10 border-b border-emerald-50">
          <div className="flex flex-col">
            <div className="flex items-center gap-3">
               <Activity size={16} className="text-emerald-500 animate-pulse" />
               <h1 className="text-[10px] font-black uppercase tracking-[0.4em] text-emerald-950/40">Diagnostic Context</h1>
            </div>
            <span className="text-sm font-black text-emerald-950 uppercase tracking-widest mt-1">
              {activeSession?.title || 'System Standby'}
            </span>
          </div>

          <div className="flex items-center gap-4">
             <div className="flex items-center gap-2 px-4 py-2 bg-emerald-50 rounded-full">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[9px] font-black uppercase tracking-widest text-emerald-800">Vision Engine Alpha</span>
             </div>
             <div className="w-[1px] h-6 bg-emerald-100"></div>
             <button className="p-2.5 text-emerald-900/20 hover:text-emerald-900 transition-colors">
                <Search size={20} />
             </button>
             <button className="p-2.5 text-emerald-900/20 hover:text-emerald-900 transition-colors">
                <Settings size={20} />
             </button>
          </div>
        </header>

        <ChatWindow 
          messages={activeSession?.messages || []} 
          isLoading={isLoading} 
        />

        <ChatInput onSend={handleSendMessage} disabled={isLoading} />
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <MainApp />
    </AuthProvider>
  );
};

export default App;

