const MainApp: React.FC = () => {
  const { currentUser } = useAuth();
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentView, setCurrentView] = useState<'diagnostic' | 'dashboard'>('diagnostic');
  const [showNotification, setShowNotification] = useState<string | null>(null);

  useEffect(() => {
    if (currentUser && sessions.length === 0) {
      handleNewChat();
    }
  }, [currentUser]);

  const handleNewChat = useCallback(() => {
    const newSession: ChatSession = {
      id: crypto.randomUUID(),
      title: "Bio-Specimen " + (sessions.length + 1).toString().padStart(3, '0'),
      messages: [],
      createdAt: new Date(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
    setCurrentView('diagnostic');
  }, [sessions.length]);

  const handleSelectSession = useCallback((id: string) => {
    setActiveSessionId(id);
  }, []);

  const handleSendMessage = async (content: string, image?: { mimeType: string, data: string, url: string }) => {
    if (!activeSessionId) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content,
      timestamp: new Date(),
      imageUrl: image?.url
    };

    setSessions(prev => prev.map(s => {
      if (s.id === activeSessionId) {
        const isFirstMessage = s.messages.length === 0;
        let newTitle = s.title;
        if (isFirstMessage) {
          newTitle = image ? "Visual Identity" : content.slice(0, 18).toUpperCase();
        }
        return { ...s, messages: [...s.messages, userMsg], title: newTitle };
      }
      return s;
    }));

    setIsLoading(true);

    const activeSession = sessions.find(s => s.id === activeSessionId);
    // Fixed: Map 'assistant' role to 'model' for Gemini API compatibility as assistant is not a valid role
    const apiHistory = (activeSession?.messages || []).map(m => ({
      role: m.role === 'assistant' ? 'model' : 'user',
      parts: [{ text: m.content }]
    }));

    const aiResponseText = await generateAIResponse(
      content, 
      apiHistory, 
      image ? { mimeType: image.mimeType, data: image.data } : undefined
    );

    const assistantMsg: Message = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiResponseText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s
    ));

    setIsLoading(false);
  };

  if (!currentUser) {
    return <AuthPortal />;
  }

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-[#fcfdfd] overflow-hidden selection:bg-emerald-500/20">
      <Sidebar 
        sessions={sessions} 
        activeSessionId={activeSessionId} 
        onNewChat={handleNewChat}
        onSelectSession={handleSelectSession}
        currentView={currentView}
        onSetView={setCurrentView}
      />

      <main className="flex-1 flex flex-col relative h-full">
        {showNotification && (
          <div className="fixed top-24 left-1/2 -translate-x-1/2 z-[60] bg-[#022218] text-emerald-400 px-8 py-3.5 rounded-full shadow-[0_20px_50px_rgba(0,0,0,0.3)] border border-emerald-900/50 flex items-center gap-3 animate-in fade-in slide-in-from-top-4">
            <CheckCircle size={18} />
            <span className="text-xs font-black uppercase tracking-widest">{showNotification}</span>
          </div>
        )}

        <header className="h-24 flex items-center justify-between px-12 bg-white/60 backdrop-blur-xl sticky top-0 z-10 border-b border-emerald-50">
          <div className="flex flex-col">
            <div className="flex items-center gap-3">
               <Activity size={14} className="text-emerald-500" />
               <h1 className="text-[9px] font-black uppercase tracking-[0.5em] text-emerald-950/30">System Diagnostics</h1>
            </div>
            <span className="text-lg font-black text-emerald-950 uppercase tracking-tighter mt-1">
              {currentView === 'dashboard' ? 'Laboratory Core' : (activeSession?.title || 'Gateway Standby')}
            </span>
          </div>

          <div className="flex items-center gap-6">
             <div className="hidden lg:flex items-center gap-2 px-5 py-2.5 bg-emerald-50 rounded-2xl border border-emerald-100 shadow-sm">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[10px] font-black uppercase tracking-widest text-emerald-800">Neural Sync Active</span>
             </div>
             <div className="flex items-center gap-2">
               <button className="p-3 bg-white hover:bg-emerald-50 border border-emerald-50 rounded-2xl text-emerald-900/30 hover:text-emerald-900 transition-all shadow-sm">
                  <Search size={18} />
               </button>
               <button className="p-3 bg-white hover:bg-emerald-50 border border-emerald-50 rounded-2xl text-emerald-900/30 hover:text-emerald-900 transition-all shadow-sm">
                  <Settings size={18} />
               </button>
             </div>
          </div>
        </header>

        {currentView === 'diagnostic' ? (
          <>
            <ChatWindow 
              messages={activeSession?.messages || []} 
              isLoading={isLoading} 
            />
            <ChatInput onSend={handleSendMessage} disabled={isLoading} />
          </>
        ) : (
          <LabDashboard />
        )}
      </main>
    </div>
  );
};

