export const generateAIResponse = async (
  prompt: string, 
  history: { role: string; parts: ( { text: string } | MediaPart )[] }[],
  image?: { mimeType: string; data: string }
): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    const contents: any[] = [...history];
    const currentParts: any[] = [{ text: prompt }];

    if (image) {
      currentParts.push({
        inlineData: {
          mimeType: image.mimeType,
          data: image.data,
        }
      });
    }

    contents.push({ role: 'user', parts: currentParts });

    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: contents,
      config: {
        systemInstruction: `Aapka naam "FloraExpert" hai. Aap ek friendly aur samajhdar plant advisor hain jo kisanon aur paudha premion ki madad karte hain. 

        RULES FOR RESPONSE:
        1. LANGUAGE: Use professional but simple language (Hinglish or English). Avoid very hard technical words.
        2. STRUCTURE: Use clear points and emojis.
           - ## 🌱 Paudha Pehchan: (Identification)
           - ## 🏥 Kya Dikkat Hai?: (Problem/Disease)
           - ## 🛠️ Kya Kare?: (Step-by-step solution)
           - ## 💧 Zaruri Cheezein: (Light, Water, Soil - use simple table)
        3. TONE: Encouraging, helpful, and humble.
        4. IMAGES: If an image is provided, focus on what you see in the photo clearly.
        5. AUTOMATION: If relevant, mention that you can send regular updates via email for this plant.

        Aapka maksad hai ki koi bhi aam aadmi apne paudhe ki dekhbhal asani se kar sake.`,
        temperature: 0.7,
        topP: 0.9,
      }
    });

    return response.text || "Maaf kijiye, hum is report ko pura nahi kar paye. Kripya fir se try kare.";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Error: System abhi busy hai. Kripya thodi der baad try kare.";
  }
};

