const MainApp: React.FC = () => {
  const { currentUser } = useAuth();
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentView, setCurrentView] = useState<'diagnostic' | 'dashboard'>('diagnostic');
  const [automationEnabled] = useState(true);

  useEffect(() => {
    if (currentUser && sessions.length === 0) {
      handleNewChat();
    }
  }, [currentUser]);

  const handleNewChat = useCallback(() => {
    const newSession: ChatSession = {
      id: crypto.randomUUID(),
      title: "Log " + (sessions.length + 1).toString().padStart(3, '0'),
      messages: [],
      createdAt: new Date(),
    };
    setSessions(prev => [newSession, ...prev]);
    setActiveSessionId(newSession.id);
    setCurrentView('diagnostic');
  }, [sessions.length]);

  const handleSelectSession = useCallback((id: string) => {
    setActiveSessionId(id);
  }, []);

  const handleSendMessage = async (content: string, image?: { mimeType: string, data: string, url: string }) => {
    if (!activeSessionId) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content,
      timestamp: new Date(),
      imageUrl: image?.url
    };

    setSessions(prev => prev.map(s => {
      if (s.id === activeSessionId) {
        const isFirstMessage = s.messages.length === 0;
        let newTitle = s.title;
        if (isFirstMessage) {
          newTitle = image ? "Visual Analysis" : content.slice(0, 15).toUpperCase();
        }
        return { ...s, messages: [...s.messages, userMsg], title: newTitle };
      }
      return s;
    }));

    setIsLoading(true);

    const activeSession = sessions.find(s => s.id === activeSessionId);
    const apiHistory = (activeSession?.messages || []).map(m => ({
      role: m.role === 'assistant' ? 'model' : 'user',
      parts: [{ text: m.content }]
    }));

    const aiResponseText = await generateAIResponse(
      content, 
      apiHistory, 
      image ? { mimeType: image.mimeType, data: image.data } : undefined
    );

    const assistantMsg: Message = {
      id: crypto.randomUUID(),
      role: 'assistant',
      content: aiResponseText,
      timestamp: new Date()
    };

    setSessions(prev => prev.map(s => 
      s.id === activeSessionId ? { ...s, messages: [...s.messages, assistantMsg] } : s
    ));

    setIsLoading(false);
  };

  if (!currentUser) {
    return <AuthPortal />;
  }

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-[#fcfdfd] overflow-hidden selection:bg-emerald-500/20">
      <Sidebar 
        sessions={sessions} 
        activeSessionId={activeSessionId} 
        onNewChat={handleNewChat}
        onSelectSession={handleSelectSession}
        currentView={currentView}
        onSetView={setCurrentView}
        automationEnabled={automationEnabled}
      />

      <main className="flex-1 flex flex-col relative h-full">
        <header className="h-20 flex items-center justify-between px-10 bg-white/80 backdrop-blur-md sticky top-0 z-10 border-b border-emerald-50">
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase text-emerald-600 tracking-[0.3em]">Neural Interface</span>
            <span className="text-xl font-black text-emerald-950 tracking-tighter mt-0.5">
              {currentView === 'dashboard' ? 'Health Dashboard' : (activeSession?.title || 'System Initialization')}
            </span>
          </div>

          <div className="flex items-center gap-4">
             <div className="hidden md:flex items-center gap-2 px-4 py-2 bg-emerald-50 rounded-full border border-emerald-100">
                <div className="w-1.5 h-1.5 rounded-full bg-emerald-500 animate-pulse"></div>
                <span className="text-[10px] font-bold text-emerald-800 uppercase tracking-widest">Network Secure</span>
             </div>
             <button className="p-3 bg-white hover:bg-emerald-50 rounded-xl text-emerald-900/20 hover:text-emerald-900 transition-all border border-emerald-50">
               <Bell size={18} />
             </button>
          </div>
        </header>

        {currentView === 'diagnostic' ? (
          <>
            <ChatWindow 
              messages={activeSession?.messages || []} 
              isLoading={isLoading} 
            />
            <ChatInput onSend={handleSendMessage} disabled={isLoading} />
          </>
        ) : (
          <LabDashboard automationEnabled={automationEnabled} />
        )}
      </main>
    </div>
  );
};

