          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase text-emerald-600 tracking-[0.3em]">Network Access</span>
            <span className="text-xl font-black text-emerald-950 tracking-tighter mt-0.5 uppercase">
              {currentView === 'dashboard' ? 'Reports' : (activeSession?.title || 'Initialization')}
