import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { Leaf, Mail, Lock, User, ArrowRight, Loader2, ShieldCheck, AlertTriangle } from 'lucide-react';

const AuthPortal: React.FC = () => {
  const { login, register } = useAuth();
  const [loading, setLoading] = useState(false);
  const [isRegistering, setIsRegistering] = useState(false);
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');
  const [error, setError] = useState<{message: string, isConfig?: boolean} | null>(null);

  const handleAuth = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setLoading(true);

    try {
      if (isRegistering) {
        if (!name) throw new Error('Researcher name is required.');
        await register(email, password, name);
      } else {
        await login(email, password);
      }
    } catch (err: any) {
      console.error(err);
      let msg = "Authentication failed.";
      let isConfig = false;

      if (err.code === 'auth/operation-not-allowed') {
        msg = "Email/Password sign-in is not enabled in Firebase Console. Go to Authentication > Sign-in method and enable 'Email/Password'.";
        isConfig = true;
      } else if (err.code === 'auth/user-not-found') {
        msg = "User profile not found.";
      } else if (err.code === 'auth/wrong-password') {
        msg = "Invalid encrypted key (password).";
      } else if (err.code === 'auth/email-already-in-use') {
        msg = "Email identity already exists.";
      } else if (err.code === 'auth/weak-password') {
        msg = "Password must be at least 6 characters.";
      } else if (err.message) {
        msg = err.message;
      }

      setError({ message: msg, isConfig });
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="flex h-screen w-full bg-[#f8fbf9] overflow-hidden">
      {/* Immersive Visual Side */}
      <div className="hidden lg:flex w-[55%] bg-[#021811] relative overflow-hidden items-center justify-center p-24">
