           </div>

           <div className="space-y-6 max-w-lg">
              <h2 className="text-4xl font-bold text-emerald-50 leading-tight">Professional Botanical Neural Networking.</h2>
              <p className="text-emerald-100/40 text-xl font-medium leading-relaxed">
                Unlock world-class plant classification, disease diagnosis, and automated gardening sync.
              </p>
           </div>
        </div>
      </div>

      {/* Auth Form Side */}
      <div className="w-full lg:w-[45%] flex items-center justify-center p-8 md:p-24 relative overflow-y-auto no-scrollbar">
        <div className="w-full max-w-md space-y-12">
          <div className="text-center lg:text-left space-y-4">
            <h3 className="text-4xl font-black text-emerald-950 tracking-tighter uppercase">
