                    className="w-full pl-14 pr-6 py-5 bg-white border border-emerald-100 rounded-[2rem] focus:ring-8 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                    placeholder="Researcher Name"
                  />
                </div>
              </div>
            )}

            <div className="space-y-3">
              <label className="text-[10px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Work Email</label>
              <div className="relative group">
