            <div className="space-y-3">
              <label className="text-[10px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Encrypted Key</label>
              <div className="relative group">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-200 group-focus-within:text-emerald-600 transition-colors" size={20} />
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white border border-emerald-100 rounded-[2rem] focus:ring-8 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                  placeholder="••••••••••••"
                />
              </div>
            </div>

            {error && (
              <div className={`p-5 border rounded-3xl text-[10px] font-black flex items-start gap-3 ${error.isConfig ? 'bg-amber-50 border-amber-200 text-amber-700' : 'bg-red-50 border-red-100 text-red-600'}`}>
                {error.isConfig ? <AlertTriangle className="shrink-0" size={16} /> : <div className="w-2 h-2 bg-red-400 rounded-full animate-pulse mt-1" />}
                <span className="leading-normal">{error.message.toUpperCase()}</span>
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full py-6 bg-[#021811] text-emerald-400 font-black rounded-[2rem] hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50"
            >
              {loading ? <Loader2 className="animate-spin" size={24} /> : (
                <>
                  <span className="uppercase tracking-[0.2em]">{isRegistering ? 'Initialize' : 'Verify Access'}</span>
                  <ArrowRight size={22} />
                </>
              )}
            </button>
          </form>

          <div className="text-center">
            <button
              onClick={() => setIsRegistering(!isRegistering)}
              className="text-xs font-black text-emerald-950/40 hover:text-emerald-950 transition-colors uppercase tracking-[0.2em]"
            >
              {isRegistering ? 'Already registered? Log In' : 'New researcher? Register'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPortal;

import React, { useState, useCallback, useEffect } from 'react';
