const MainApp: React.FC = () => {
  const { currentUser, signOut } = useAuth();
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [activeSessionId, setActiveSessionId] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [currentView, setCurrentView] = useState<'diagnostic' | 'dashboard'>('diagnostic');
  const [dbError, setDbError] = useState<string | null>(null);

  // Sync sessions from Firestore
  useEffect(() => {
    if (!currentUser) return;

    const q = query(
      collection(db, `users/${currentUser.uid}/sessions`),
      orderBy('createdAt', 'desc'),
      limit(10)
    );

    const unsubscribe = onSnapshot(q, (snapshot) => {
      setDbError(null);
      const sessionList: ChatSession[] = [];
      snapshot.forEach((doc) => {
        const data = doc.data();
        sessionList.push({
          id: doc.id,
          title: data.title,
          messages: data.messages || [],
          createdAt: data.createdAt?.toDate() || new Date(),
        });
      });
      setSessions(sessionList);

      if (!activeSessionId && sessionList.length > 0) {
        setActiveSessionId(sessionList[0].id);
      }
    }, (error) => {
      console.error("Firestore Listener Error:", error);
      if (error.code === 'permission-denied') {
        setDbError("Database access denied. Please ensure your Firestore Security Rules are published and allow access to authenticated users.");
      } else {
        setDbError("Database error. Ensure Cloud Firestore is enabled in your Firebase Console.");
      }
    });

    return unsubscribe;
  }, [currentUser]);

  const handleNewChat = useCallback(async () => {
    if (!currentUser) return;
    try {
      const newId = crypto.randomUUID();
      const newSessionRef = doc(db, `users/${currentUser.uid}/sessions`, newId);

      await setDoc(newSessionRef, {
        title: "New Checkup",
        messages: [],
        createdAt: serverTimestamp(),
        userId: currentUser.uid
      });

      setActiveSessionId(newId);
      setCurrentView('diagnostic');
    } catch (err: any) {
      console.error("Failed to create new chat:", err);
      if (err.code === 'permission-denied') {
        alert("Permission denied. Check Firestore Rules.");
      } else {
        alert("Firestore API might be disabled. Check Firebase Console.");
      }
    }
  }, [currentUser]);

  const handleSendMessage = async (content: string, image?: { mimeType: string, data: string, url: string }) => {
    if (!activeSessionId || !currentUser) return;

    const userMsg: Message = {
      id: crypto.randomUUID(),
      role: 'user',
      content,
      timestamp: new Date(),
      imageUrl: image?.url
    };

    const currentSession = sessions.find(s => s.id === activeSessionId);
    const updatedMessages = [...(currentSession?.messages || []), userMsg];

    // Update locally and in Firestore
    const sessionRef = doc(db, `users/${currentUser.uid}/sessions`, activeSessionId);

    let newTitle = currentSession?.title || "New Checkup";
    if (updatedMessages.length === 1) {
       newTitle = image ? "Image Log" : content.slice(0, 15).toUpperCase();
    }

    try {
      await updateDoc(sessionRef, {
        messages: updatedMessages,
        title: newTitle
      });

      setIsLoading(true);

      const apiHistory = updatedMessages.map(m => ({
        role: m.role === 'assistant' ? 'model' : 'user',
        parts: [{ text: m.content }]
      }));

      const aiResponseText = await generateAIResponse(
        content, 
        apiHistory, 
        image ? { mimeType: image.mimeType, data: image.data } : undefined
      );

      const assistantMsg: Message = {
        id: crypto.randomUUID(),
        role: 'assistant',
        content: aiResponseText,
        timestamp: new Date()
      };

      await updateDoc(sessionRef, {
        messages: [...updatedMessages, assistantMsg]
      });
    } catch (err) {
      console.error("Message send failed:", err);
      alert("Database error: could not sync message. Check permissions/API status.");
    } finally {
      setIsLoading(false);
    }
  };

  if (!currentUser) return <AuthPortal />;

  const activeSession = sessions.find(s => s.id === activeSessionId);

  return (
    <div className="flex h-screen w-full bg-[#fcfdfd] overflow-hidden">
      <Sidebar 
        sessions={sessions} 
        activeSessionId={activeSessionId} 
        onNewChat={handleNewChat}
        onSelectSession={setActiveSessionId}
        currentView={currentView}
        onSetView={setCurrentView}
        automationEnabled={true}
      />

      <main className="flex-1 flex flex-col relative h-full">
        <header className="h-20 flex items-center justify-between px-10 bg-white border-b border-emerald-50">
          <div className="flex flex-col">
            <span className="text-[10px] font-black uppercase text-emerald-600 tracking-[0.3em]">Network Access</span>
            <span className="text-xl font-black text-emerald-950 tracking-tighter mt-0.5 uppercase">
              {currentView === 'dashboard' ? 'Reports' : (activeSession?.title || 'Initialization')}
            </span>
          </div>
          <button onClick={() => signOut()} className="px-4 py-2 bg-emerald-50 text-emerald-600 text-[10px] font-bold rounded-lg uppercase tracking-widest border border-emerald-100">
             Secure Logout
          </button>
        </header>

        {dbError && (
          <div className="mx-10 mt-6 p-4 bg-amber-50 border border-amber-200 rounded-2xl flex items-start gap-3 shadow-sm animate-in fade-in slide-in-from-top-4">
            <AlertTriangle className="text-amber-600 shrink-0 mt-0.5" size={18} />
            <div className="flex flex-col gap-1">
              <p className="text-xs font-black text-amber-900 uppercase tracking-widest">Database Sync Issue</p>
              <p className="text-xs text-amber-700 font-medium leading-relaxed">{dbError}</p>
            </div>
          </div>
        )}

        {currentView === 'diagnostic' ? (
          <>
            <ChatWindow messages={activeSession?.messages || []} isLoading={isLoading} />
            <ChatInput onSend={handleSendMessage} disabled={isLoading} />
          </>
        ) : (
          <LabDashboard automationEnabled={true} />
        )}
      </main>
    </div>
  );
};

const App: React.FC = () => {
  return (
    <AuthProvider>
      <MainApp />
    </AuthProvider>
  );
};

