    let timer: any;
    if (resendTimer > 0) {
      timer = setInterval(() => setResendTimer(prev => prev - 1), 1000);
    }
    return () => clearInterval(timer);
  }, [resendTimer]);

  const sendOtpEmail = async (targetEmail: string, code: string) => {
    try {
      await Email.send({
        Host: "smtp.gmail.com",
        Username: "ankitsingh14175@gmail.com",
        Password: "qmlp imha krlz bhsa",
        To: targetEmail,
        From: "ankitsingh14175@gmail.com",
        Subject: "Botanical Portal Verification Code",
        Body: `
          <div style="font-family: sans-serif; padding: 40px; background-color: #f8fbf9; color: #064e3b; border-radius: 20px; border: 1px solid #e2e8f0;">
            <h2 style="color: #10b981; margin-bottom: 20px;">Identity Verification</h2>
            <p>Welcome to <b>FloraExpert Intelligence</b>.</p>
            <p>Your unique access code for registration is:</p>
            <div style="font-size: 32px; font-weight: 900; letter-spacing: 10px; padding: 20px; background-color: #ffffff; border: 1px solid #10b981; border-radius: 12px; margin: 20px 0; text-align: center;">
              ${code}
            </div>
            <p style="font-size: 12px; color: #94a3b8;">If you did not request this, please ignore this email.</p>
          </div>
        `
      });
      return true;
    } catch (e) {
      console.error("SMTP Error:", e);
      return false;
    }
  };

