                </button>

                <div className="flex items-center justify-between px-2">
                  <button 
                    onClick={() => { setStep('info'); setOtp(['','','','','','']); }}
                    className="text-[10px] font-black text-emerald-900/40 hover:text-emerald-900 uppercase tracking-widest transition-colors"
                  >
                    Edit Credentials
                  </button>
                  <button 
                    onClick={handleResend}
                    disabled={resendTimer > 0 || loading}
                    className={`flex items-center gap-2 text-[10px] font-black uppercase tracking-widest transition-colors ${resendTimer > 0 ? 'text-emerald-900/20' : 'text-emerald-600 hover:text-emerald-800'}`}
