                      </div>
                    </div>
                    <button 
                      type="button"
                      onClick={initializeSmtpSystem}
                      className="w-full py-4 bg-amber-100 text-amber-700 rounded-2xl text-[10px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-amber-200 transition-colors"
                    >
                      <Zap size={14} />
                      Retry Security Handshake
                    </button>
                  </div>
                )}

                <button
                  type="submit"
                  disabled={loading}
                  className="w-full py-6 bg-[#021811] text-emerald-400 font-black rounded-[2rem] hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50 shadow-2xl shadow-emerald-950/20"
