                  <input
                    key={i}
                    ref={(el) => { otpRefs.current[i] = el; }}
                    type="text"
                    value={digit}
                    onChange={(e) => handleOtpChange(i, e.target.value)}
                    onKeyDown={(e) => handleOtpKeyDown(i, e)}
                    className="w-full h-16 bg-white border-2 border-emerald-100 rounded-2xl text-center text-2xl font-black text-emerald-950 outline-none transition-all focus:border-emerald-500 focus:ring-8 focus:ring-emerald-500/5 shadow-sm"
                    maxLength={1}
                  />
                ))}
              </div>

              {error && (
                <div className="p-4 bg-red-50 border border-red-100 rounded-2xl text-[10px] font-black text-red-600 flex items-center gap-3 animate-in fade-in">
                  <AlertTriangle size={14} className="shrink-0" />
                  {error.message.toUpperCase()}
                </div>
              )}

              <div className="space-y-4">
                <button
                  onClick={handleVerifyOtp}
                  disabled={loading || otp.some(d => !d)}
                  className="w-full py-6 bg-[#021811] text-emerald-400 font-black rounded-[2rem] hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-20 shadow-2xl shadow-emerald-950/20"
                >
                  {loading ? <Loader2 className="animate-spin" size={24} /> : (
                    <>
                      <CheckCircle2 size={22} />
                      <span className="uppercase tracking-[0.2em]">Validate Researcher</span>
                    </>
