              <h2 className="text-4xl font-bold text-emerald-50 leading-tight tracking-tight">Professional Botanical Neural Networking.</h2>
              <p className="text-emerald-100/40 text-xl font-medium leading-relaxed">
                Unlock world-class plant classification, disease diagnosis, and automated gardening sync.
              </p>
           </div>
        </div>
      </div>

      {/* Auth Form Side */}
      <div className="w-full lg:w-[45%] flex items-center justify-center p-8 md:p-24 relative overflow-y-auto no-scrollbar">
        <div className="w-full max-w-md space-y-12 animate-in fade-in slide-in-from-right-4 duration-500">

          <div className="text-center lg:text-left space-y-4">
            <h3 className="text-4xl font-black text-emerald-950 tracking-tighter uppercase">
              {isRegistering ? 'Initialize Identity' : 'Gateway Access'}
            </h3>
            <p className="text-emerald-900/30 text-sm font-bold uppercase tracking-[0.2em]">
              {isRegistering ? 'Register your profile in the project cloud.' : 'Verify credentials for botanical entry.'}
            </p>
          </div>

          <form onSubmit={handleAuthSubmit} className="space-y-6">
            {isRegistering && (
              <div className="space-y-3">
                <label className="text-[10px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Full Name</label>
                <div className="relative group">
                  <User className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-200 group-focus-within:text-emerald-600 transition-colors" size={20} />
                  <input
                    type="text"
                    required
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full pl-14 pr-6 py-5 bg-white border border-emerald-100 rounded-[2rem] focus:ring-8 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                    placeholder="Researcher Name"
                  />
                </div>
              </div>
            )}

            <div className="space-y-3">
              <label className="text-[10px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Work Email</label>
              <div className="relative group">
                <Mail className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-200 group-focus-within:text-emerald-600 transition-colors" size={20} />
                <input
                  type="email"
                  required
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white border border-emerald-100 rounded-[2rem] focus:ring-8 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                  placeholder="name@email.com"
                />
              </div>
            </div>

            <div className="space-y-3">
              <label className="text-[10px] font-black text-emerald-900/40 uppercase tracking-[0.3em] ml-1">Encrypted Key</label>
              <div className="relative group">
                <Lock className="absolute left-5 top-1/2 -translate-y-1/2 text-emerald-200 group-focus-within:text-emerald-600 transition-colors" size={20} />
                <input
                  type="password"
                  required
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  className="w-full pl-14 pr-6 py-5 bg-white border border-emerald-100 rounded-[2rem] focus:ring-8 focus:ring-emerald-500/5 outline-none font-bold text-emerald-950 transition-all shadow-sm"
                  placeholder="••••••••••••"
                />
              </div>
            </div>

            {error && (
              <div className="p-5 bg-red-50 border border-red-100 rounded-3xl text-[10px] font-black flex items-start gap-3 text-red-600 animate-in slide-in-from-top-1">
                <AlertTriangle size={14} className="shrink-0 mt-0.5" />
                <span className="leading-normal">{error.message.toUpperCase()}</span>
              </div>
            )}

            <button
              type="submit"
              disabled={loading}
              className="w-full py-6 bg-[#021811] text-emerald-400 font-black rounded-[2rem] hover:bg-black transition-all flex items-center justify-center gap-4 active:scale-95 disabled:opacity-50 shadow-2xl shadow-emerald-950/20"
            >
              {loading ? <Loader2 className="animate-spin" size={24} /> : (
                <>
                  <span className="uppercase tracking-[0.2em]">{isRegistering ? 'Register Account' : 'Authorize Entrance'}</span>
                  <ArrowRight size={22} />
                </>
              )}
            </button>
          </form>

          <div className="text-center">
            <button
              onClick={() => { setIsRegistering(!isRegistering); setError(null); }}
              className="text-xs font-black text-emerald-950/40 hover:text-emerald-950 transition-colors uppercase tracking-[0.2em]"
            >
              {isRegistering ? 'Member of the core? Log In' : 'Join botanical network? Register'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default AuthPortal;
